import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.util.Scanner;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userName = scanner.nextLine();

        // Properly sanitizing and escaping user input
        String safeUserName = "";
        try {
            safeUserName = ESAPI.encoder().encodeForHTML(userName);
        } catch (EncodingException e) {
            System.err.println("Error encoding user input: " + e.getMessage());
            System.exit(1);
        }

        System.out.println("<p>Welcome, " + safeUserName + "!</p>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
